const now = new Date();
const today = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const yesterday = new Date(now - 86400000).toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const dayOfWeek = now.toLocaleDateString('en-US', { weekday: 'long', timeZone: 'America/Chicago' });
return [{ json: { today, yesterday, dayOfWeek } }];

const { today, yesterday, dayOfWeek } = $('Set Dates').first().json;

// Read MTL content from S3 binary output
let mtlContent = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  mtlContent = buf.toString('utf-8');
} catch(e) {}

// Parse tasks — correct single-escaped regex, due date is optional
const overdue = [];
const dueToday = [];
const priorityANoDate = [];
const allTasks = [];

const re = /^- \[ \] (.+?)\[area:: (\w+)\].*?\[priority:: ([ABC])\](?:.*?\[due:: (\d{4}-\d{2}-\d{2})\])?/gm;
let m;
while ((m = re.exec(mtlContent)) !== null) {
  const task = m[1].trim();
  const area = m[2];
  const priority = m[3];
  const due = m[4] || null;
  const item = { task, area, priority, due };
  allTasks.push(item);
  if (due) {
    if (due < today) {
      item.daysOverdue = Math.floor((new Date(today) - new Date(due)) / 86400000);
      overdue.push(item);
    } else if (due === today) {
      dueToday.push(item);
    }
  } else if (priority === 'A') {
    priorityANoDate.push(item);
  }
}

// Sort: overdue by priority then daysOverdue desc; dueToday by priority
overdue.sort((a, b) => {
  if (a.priority !== b.priority) return a.priority < b.priority ? -1 : 1;
  return b.daysOverdue - a.daysOverdue;
});
dueToday.sort((a, b) => a.priority < b.priority ? -1 : a.priority > b.priority ? 1 : 0);

// Quick wins: up to 3 Priority C tasks not past due
const quickWins = allTasks.filter(t => t.priority === 'C' && (!t.due || t.due >= today)).slice(0, 3);

// Determine #1 priority task
let topPriorityTask = 'Review your Master Task List and set your intention for today.';
if (overdue.find(t => t.priority === 'A')) {
  const top = overdue.find(t => t.priority === 'A');
  topPriorityTask = top.task + ' [' + top.area + '] — ' + top.daysOverdue + 'd overdue';
} else if (dueToday.find(t => t.priority === 'A')) {
  const top = dueToday.find(t => t.priority === 'A');
  topPriorityTask = top.task + ' [' + top.area + ']';
} else if (overdue.length > 0) {
  const top = overdue[0];
  topPriorityTask = top.task + ' [' + top.area + '] — ' + top.daysOverdue + 'd overdue';
} else if (dueToday.length > 0) {
  topPriorityTask = dueToday[0].task + ' [' + dueToday[0].area + ']';
} else if (priorityANoDate.length > 0) {
  topPriorityTask = priorityANoDate[0].task + ' [' + priorityANoDate[0].area + ']';
}

// Read yesterday log
let capturedTasks = 0, capturedArticles = 0;
try {
  const logBuf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (logBuf) {
    const log = JSON.parse(logBuf.toString('utf-8'));
    capturedTasks = log.tasks_extracted || log.task_count || 0;
    capturedArticles = log.articles_queued || log.article_count || 0;
  }
} catch(e) {}

const areaEmoji = { faith:'🙏', family:'👨‍👩‍👧', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🎯' };

function priorityBadge(p) {
  const colors = { A:'#dc2626', B:'#d97706', C:'#6b7280' };
  return '<span style="display:inline-block;padding:2px 6px;border-radius:3px;font-size:10px;font-weight:bold;background:' + colors[p] + ';color:white">' + p + '</span>';
}

function taskCard(t, borderColor) {
  const dueTxt = t.due ? '<span style="color:#6b7280;font-size:11px"> · due ' + t.due + '</span>' : '';
  const overdueBadge = t.daysOverdue ? ' <span style="color:#dc2626;font-weight:bold;font-size:11px">' + t.daysOverdue + 'd overdue</span>' : '';
  const emoji = areaEmoji[t.area] || '📌';
  return '<div style="border-left:4px solid ' + borderColor + ';background:white;padding:12px 14px;margin:4px 0;border-radius:0 4px 4px 0">'
    + '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
    + priorityBadge(t.priority)
    + '<span style="font-size:13px;font-weight:500">' + emoji + ' ' + t.task + '</span>'
    + overdueBadge + dueTxt
    + '</div>'
    + '<div style="font-size:11px;color:#9ca3af;margin-top:4px;text-transform:capitalize">' + t.area + '</div>'
    + '</div>';
}

const rocks = [
  { area:'faith', label:'Social media Bible study (4 sessions)', pct:35 },
  { area:'family', label:'Marriage Alignment + bi-weekly check-in', pct:0 },
  { area:'business', label:'MVP — website, offer, 3 outreach convos', pct:25 },
  { area:'work', label:'Deliver Union project', pct:0 },
  { area:'health', label:'Hip decision + 3x/week gym ×8 weeks', pct:0 },
];

function progressBar(pct) {
  const color = pct >= 75 ? '#16a34a' : pct >= 40 ? '#d97706' : '#dc2626';
  return '<div style="background:#e5e7eb;border-radius:4px;height:6px;margin-top:4px"><div style="background:' + color + ';width:' + pct + '%;height:6px;border-radius:4px"></div></div>';
}

let html = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#f5f5f5;padding:0">';

// Header
html += '<div style="background:#1a1a2e;color:white;padding:24px 20px;border-radius:8px 8px 0 0">'
  + '<h1 style="margin:0;font-size:22px;font-weight:700">🌅 Good morning, Aaron</h1>'
  + '<p style="margin:6px 0 0;opacity:0.75;font-size:14px">' + dayOfWeek + ', ' + today + '</p>'
  + '</div>';

// Top Priority CTA
html += '<div style="background:#dc2626;color:white;padding:14px 20px;margin:2px 0">'
  + '<p style="margin:0;font-size:10px;text-transform:uppercase;letter-spacing:1.5px;opacity:0.85">🎯 TODAY\'S #1 PRIORITY</p>'
  + '<p style="margin:6px 0 0;font-size:15px;font-weight:bold;line-height:1.4">' + topPriorityTask + '</p>'
  + '</div>';

// Overdue section
html += '<div style="padding:16px 20px;background:#fff8f8;margin-top:2px">';
if (overdue.length > 0) {
  html += '<h2 style="margin:0 0 10px;font-size:15px;color:#dc2626;font-weight:700">🔥 Overdue — ' + overdue.length + ' task' + (overdue.length > 1 ? 's' : '') + '</h2>';
  html += overdue.map(t => taskCard(t, '#dc2626')).join('');
} else {
  html += '<div style="border-left:4px solid #16a34a;background:white;padding:12px 14px;border-radius:0 4px 4px 0"><span style="color:#16a34a;font-weight:bold">✅ No overdue tasks — you\'re ahead of the game!</span></div>';
}
html += '</div>';

// Due Today section
html += '<div style="padding:16px 20px;background:#fffbf0;margin-top:2px">';
if (dueToday.length > 0) {
  html += '<h2 style="margin:0 0 10px;font-size:15px;color:#d97706;font-weight:700">📅 Due Today — ' + dueToday.length + ' task' + (dueToday.length > 1 ? 's' : '') + '</h2>';
  html += dueToday.map(t => taskCard(t, '#d97706')).join('');
} else {
  html += '<div style="border-left:4px solid #d97706;background:white;padding:12px 14px;border-radius:0 4px 4px 0"><span style="color:#6b7280">📅 Nothing due today — good time to get ahead.</span></div>';
}
html += '</div>';

// Priority A — No Date section
if (priorityANoDate.length > 0) {
  html += '<div style="padding:16px 20px;background:#f0f4ff;margin-top:2px">'
    + '<h2 style="margin:0 0 10px;font-size:15px;color:#2563eb;font-weight:700">🪨 Priority A Rocks (no due date)</h2>'
    + priorityANoDate.map(t => taskCard(t, '#2563eb')).join('')
    + '</div>';
}

// Q2 Rocks Snapshot
html += '<div style="padding:16px 20px;background:#f9fafb;margin-top:2px"><h2 style="margin:0 0 12px;font-size:15px;color:#374151;font-weight:700">🎯 Q2 2026 Rocks Snapshot</h2>';
for (const rock of rocks) {
  const emoji = areaEmoji[rock.area] || '📌';
  html += '<div style="margin-bottom:10px">'
    + '<div style="display:flex;justify-content:space-between;align-items:center">'
    + '<span style="font-size:12px;font-weight:600">' + emoji + ' ' + rock.label + '</span>'
    + '<span style="font-size:11px;color:#6b7280;margin-left:8px;white-space:nowrap">' + rock.pct + '%</span>'
    + '</div>'
    + progressBar(rock.pct)
    + '</div>';
}
html += '</div>';

// Quick Wins
if (quickWins.length > 0) {
  html += '<div style="padding:16px 20px;background:#f0fdf4;margin-top:2px">'
    + '<h2 style="margin:0 0 10px;font-size:15px;color:#16a34a;font-weight:700">⚡ Quick Wins</h2>'
    + quickWins.map(t => taskCard(t, '#16a34a')).join('')
    + '</div>';
}

// Yesterday captures
if (capturedTasks > 0 || capturedArticles > 0) {
  html += '<div style="padding:16px 20px;background:#eff6ff;margin-top:2px">'
    + '<h2 style="margin:0 0 8px;font-size:15px;color:#2563eb;font-weight:700">📥 Yesterday\'s Captures</h2>'
    + '<p style="margin:4px 0;font-size:13px">📝 <strong>' + capturedTasks + '</strong> tasks extracted &nbsp;|&nbsp; 🔗 <strong>' + capturedArticles + '</strong> articles queued</p>'
    + '</div>';
}

// Footer
html += '<div style="padding:14px 20px;background:#1a1a2e;border-radius:0 0 8px 8px;text-align:center">'
  + '<p style="margin:0;color:#9ca3af;font-size:11px">' + allTasks.length + ' tasks open across 8 areas &nbsp;·&nbsp; Powered by Life OS &nbsp;·&nbsp; ' + today + '</p>'
  + '</div>';

html += '</div>';

return [{ json: {
  html,
  today,
  dayOfWeek,
  overdueCount: overdue.length,
  todayCount: dueToday.length,
  capturedTasks,
  capturedArticles,
  bodyLength: html.length
} }];

const j = $input.first().json;
const log = JSON.stringify({ workflow: 'morning-briefing', run_date: j.today, finished_at: new Date().toISOString(), status: 'success', overdue_count: j.overdueCount, today_count: j.todayCount, body_length: j.bodyLength }, null, 2);
return [{ json: { logKey: `99_System/logs/morning-briefing-${j.today}.json`, logContent: log } }];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: key.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];
